const payload = $input.item.json.body || $input.item.json;
const cliente = payload.cliente || 'GERAL';
const principios = payload.principios || [];
const friccoes = payload.friccoes || [];
const dividas = payload.dividas || [];
const data = payload.data || new Date().toISOString().substring(0, 10);
const hora = payload.hora || new Date().toTimeString().substring(0, 5);
const resumoPrincipios = principios.length > 0 ? principios.map(function(p, i) { return (i+1) + '. ' + p; }).join('
') : 'Nenhum principio novo';
const resumoFriccoes = friccoes.length > 0 ? friccoes.map(function(f, i) { return (i+1) + '. ' + f; }).join('
') : 'Nenhuma friccao';
const texto = 'Sessao encerrada -- ' + data + ' ' + hora + '
Cliente: ' + cliente + '

Principios (+' + principios.length + '):
' + resumoPrincipios + '

Friccoes (+' + friccoes.length + '):
' + resumoFriccoes + '

Dividas: ' + dividas.length;
return [{ json: { cliente: cliente, texto: texto } }];
